const chartData = $('Airtable: Find Client Chart').first()?.json ?? {};
const chatHistory = $('Airtable: Get Chat History')?.all?.() ?? [];
const msg = $('Extract Variables').first().json;
const fields = chartData.fields || chartData || {};
const clientName = fields['Client Name'] || '';

if (!clientName) {
  return [{ json: {
    clientNotFound: true,
    chatId: msg.chatId,
    userId: msg.userId,
    systemPrompt: 'You are a WhatsApp assistant for a Vedic astrology service.',
    userMessage: 'This user is NOT registered. Respond warmly saying you could not find their profile and they should contact their astrologer to register. Under 40 words.',
    recordId: null,
    messageText: msg.messageText
  }}];
}

// Vimshottari Dasha Calculator
const DASHA_SEQ = ['Ketu','Venus','Sun','Moon','Mars','Rahu','Jupiter','Saturn','Mercury'];
const DASHA_YEARS = {Ketu:7,Venus:20,Sun:6,Moon:10,Mars:7,Rahu:18,Jupiter:16,Saturn:19,Mercury:17};
const MS_DAY = 86400000, DAYS_YR = 365.25;

function parseDate(s) {
  if (!s) return null; s = String(s).trim();
  let m = s.match(/^(\d{1,2})\/(\d{1,2})\/(\d{4})$/);
  if (m) return new Date(+m[3], +m[2]-1, +m[1]);
  m = s.match(/^(\d{4})-(\d{2})-(\d{2})/);
  if (m) return new Date(+m[1], +m[2]-1, +m[3]);
  const d = new Date(s); return isNaN(d.getTime()) ? null : d;
}
function parseBalance(s) {
  if (!s) return null; s = String(s).trim();
  const pm = s.match(/^(Ketu|Venus|Sun|Moon|Mars|Rahu|Jupiter|Saturn|Mercury)\b/i);
  if (!pm) return null;
  const planet = DASHA_SEQ.find(p => p.toLowerCase() === pm[1].toLowerCase());
  if (!planet) return null;
  const y = s.match(/(\d+)\s*(?:Y(?:ear)?s?|yr)/i);
  const mo = s.match(/(\d+)\s*(?:M(?:onth)?s?|mo)\b/i);
  const d = s.match(/(\d+)\s*(?:D(?:ay)?s?)\b/i);
  if (!y && !mo && !d) return null;
  return { planet, years: y ? +y[1] : 0, months: mo ? +mo[1] : 0, days: d ? +d[1] : 0 };
}
function addPeriod(dt, y, m, d) { const r = new Date(dt); r.setFullYear(r.getFullYear()+y); r.setMonth(r.getMonth()+m); r.setDate(r.getDate()+d); return r; }
function addYrsF(dt, y) { return new Date(dt.getTime() + y * DAYS_YR * MS_DAY); }
function fmtD(d) { return String(d.getDate()).padStart(2,'0') + '/' + String(d.getMonth()+1).padStart(2,'0') + '/' + d.getFullYear(); }

function calcDasha(dobStr, balStr) {
  const dob = parseDate(dobStr), bal = parseBalance(balStr);
  if (!dob || !bal) return { error: 'Cannot parse DOB or balance' };
  const si = DASHA_SEQ.indexOf(bal.planet);
  const firstEnd = addPeriod(dob, bal.years, bal.months, bal.days);
  const firstStart = addYrsF(firstEnd, -DASHA_YEARS[bal.planet]);
  const tl = [{ planet: bal.planet, start: firstStart, end: firstEnd, displayStart: dob, partial: true }];
  const cutoff = new Date(dob.getFullYear() + 130, 0, 1);
  let cursor = firstEnd, idx = (si + 1) % 9;
  while (cursor < cutoff) { const p = DASHA_SEQ[idx], end = addYrsF(cursor, DASHA_YEARS[p]); tl.push({ planet: p, start: cursor, end, partial: false }); cursor = end; idx = (idx+1)%9; }
  const today = new Date();
  let curMD = null, nextMD = null;
  for (let i = 0; i < tl.length; i++) { if (tl[i].start <= today && today < tl[i].end) { curMD = tl[i]; nextMD = tl[i+1]||null; break; } }
  if (!curMD) return { error: 'Today outside dasha cycle' };
  const adSi = DASHA_SEQ.indexOf(curMD.planet);
  let adCursor = curMD.start, curAD = null;
  for (let i = 0; i < 9; i++) {
    const adP = DASHA_SEQ[(adSi+i)%9], dur = (DASHA_YEARS[curMD.planet]*DASHA_YEARS[adP]/120)*DAYS_YR;
    const end = new Date(adCursor.getTime() + dur * MS_DAY);
    if (adCursor <= today && today < end) { curAD = { planet: adP, start: adCursor, end }; break; }
    adCursor = end;
  }
  const daysLeft = curAD ? Math.ceil((curAD.end - today) / MS_DAY) : null;
  const mdDs = curMD.partial ? curMD.displayStart : curMD.start;
  return {
    mahadasha:     curMD.planet + ' Mahadasha (' + fmtD(mdDs) + ' - ' + fmtD(curMD.end) + ')',
    antardasha:    curAD ? curMD.planet + '-' + curAD.planet + ' Antardasha (' + fmtD(curAD.start) + ' - ' + fmtD(curAD.end) + ')' : 'NOT AVAILABLE',
    daysLeft, nextMahadasha: nextMD ? nextMD.planet + ' starts ' + fmtD(nextMD.start) : '', source: 'calculated'
  };
}

const dc = calcDasha(String(fields['Date of Birth']||''), String(fields['Balance of Dasha At Birth']||''));
// Sanity check: if calculated Mahadasha planet ≠ stored Airtable value, use Airtable
function extractPlanet(val) {
  if (!val) return '';
  const m = String(val).match(/^(Ketu|Venus|Sun|Moon|Mars|Rahu|Jupiter|Saturn|Mercury)\b/i);
  return m ? m[1].charAt(0).toUpperCase() + m[1].slice(1).toLowerCase() : '';
}
const storedMDPlanet = extractPlanet(fields['Current Mahadasha'] || '');
const calcMDPlanet   = dc.error ? '' : dc.mahadasha.split(' ')[0];
const useFallback    = !dc.error && storedMDPlanet && calcMDPlanet && storedMDPlanet !== calcMDPlanet;
if (useFallback) console.log('[DashaCalc] Sanity mismatch: calc=' + calcMDPlanet + ' stored=' + storedMDPlanet + ' — using Airtable values');

const currentMD   = (dc.error || useFallback) ? (fields['Current Mahadasha']  || 'NOT AVAILABLE') : dc.mahadasha;
const currentAD   = (dc.error || useFallback) ? (fields['Current Antardasha'] || 'NOT AVAILABLE') : dc.antardasha;
const nextMD      = (dc.error || useFallback) ? (fields['Next Mahadasha']     || '')               : dc.nextMahadasha;
const daysLeft    = (dc.error || useFallback) ? null : (dc.daysLeft || null);
const dashaSource = dc.error ? 'airtable (parse error)' : useFallback ? 'airtable (sanity check)' : 'calculated';

let conversationHistory = '';
const validHistory = chatHistory.filter(r => r.json && r.json.fields && r.json.fields.user_message);
if (validHistory.length > 0) {
  const sorted = [...validHistory].sort((a,b) => new Date(a.json.fields.timestamp||0) - new Date(b.json.fields.timestamp||0));
  conversationHistory = sorted.slice(-5).map(r => 'Client: ' + (r.json.fields.user_message||'') + '\nJyotishi: ' + (r.json.fields.ai_response||'')).join('\n\n');
}

const f = (k) => fields[k] || '';
const dashaStatus = currentMD === 'NOT AVAILABLE'
  ? 'DASHA DATA NOT AVAILABLE - do not guess dasha periods'
  : 'Mahadasha: ' + currentMD + '\nAntardasha: ' + currentAD + (daysLeft ? ' (' + daysLeft + ' days remaining)' : '') + '\nNext: ' + nextMD;

// Detect timezone from WhatsApp number country code
const whatsNum = String(fields['WhatsApp Number'] || msg.chatId || '');
let clientTZ = 'Asia/Kolkata'; // default IST
if (whatsNum.startsWith('+1'))       clientTZ = 'America/Toronto';
else if (whatsNum.startsWith('+44'))  clientTZ = 'Europe/London';
else if (whatsNum.startsWith('+61'))  clientTZ = 'Australia/Sydney';
else if (whatsNum.startsWith('+971')) clientTZ = 'Asia/Dubai';
else if (whatsNum.startsWith('+65'))  clientTZ = 'Asia/Singapore';
else if (whatsNum.startsWith('+91'))  clientTZ = 'Asia/Kolkata';
const today = new Date(new Date().toLocaleString('en-US', { timeZone: clientTZ }));
const dateStr = today.toLocaleDateString('en-GB', { weekday:'long', year:'numeric', month:'long', day:'numeric', timeZone: clientTZ });
console.log('[AssembleCtx] Client TZ: ' + clientTZ + ' (' + whatsNum.slice(0,3) + ') → ' + dateStr);

const systemPrompt =
  'You are Veteran Jyotishi - a warm, precise Vedic astrologer trained in classical Parashari Jyotish, KP, Nadi Astrology, Vimshottari Dasha, nakshatra-pada analysis, and Shodashvarga divisional charts.\n\n' +
  'Today: ' + dateStr + '\n\n' +
  'HARD RULES:\n' +
  '- NEVER ask for birth details. The complete chart data is provided.\n' +
  '- NEVER give generic readings. Cite SPECIFIC planetary factors from the chart data.\n' +
  '- Address the client as ' + clientName + '. Be warm, confident, direct.\n' +
  '- Under 160 words total.\n' +
  '- The FINAL LINE must be exactly: Ask us the remedy for this\n\n' +
  'DASHA RULES (source: ' + dashaSource + '):\n' +
  '- Use ONLY the dasha data provided. Do NOT calculate dasha yourself.\n' +
  '- If dasha says NOT AVAILABLE, write: I need to review your exact Dasha timeline - please ask your Astrologer.\n' +
  '- Quote dasha lord and dates exactly as shown.\n\n' +
  'OUTPUT FORMAT (WhatsApp plain text):\n' +
  'Line 1: ' + clientName + ', ... - one sentence naming the exact astrological factor.\n' +
  'Body: 2-4 sentences citing specific chart factors (planet, house, nakshatra, dasha lord).\n' +
  'Final line (standalone): Ask us the remedy for this\n' +
  'No headings, no bullet lists, no emoji unless client used one. *Asterisks* for 1-2 key terms only.';

const userMessage =
  '======================================\n' +
  'CHART DATA - ' + clientName.toUpperCase() + '\n' +
  '======================================\n' +
  'Lagna: ' + f('Lagna') + ' | Lagna Lord: ' + f('Lagna Lord') + '\n' +
  'Rashi: ' + f('Rashi') + ' | Nakshatra: ' + f('Nakshatra') + ' Pada ' + f('Nakshatra Pada') + '\n' +
  'Gan: ' + f('Gan') + ' | Paya: ' + f('Paya') + ' | Manglik: ' + f('Manglik') + '\n\n' +
  'PLANETARY POSITIONS:\n' + (f('Planetary Positions') || 'Not available') + '\n\n' +
  'VIMSHOTTARI DASHA:\n' + dashaStatus + '\n' +
  'Dasha Prediction: ' + (f('Current Dasha Prediction') || 'Not recorded') + '\n\n' +
  'YOGAS & DOSHAS:\n' + (f('Yogas Doshas') || 'Not recorded') + '\n\n' +
  'SADESATI: ' + (f('Sadesati Details') || 'Not applicable') + '\n\n' +
  'LUCKY FACTORS: Day: ' + f('Lucky Day') + ' | Color: ' + f('Lucky Color') + ' | Number: ' + f('Lucky Number') + ' | Stone: ' + f('Life Stone') + '\n\n' +
  'LAL KITAB REMEDIES:\n' + (f('Lalkitab Remedies') || 'Not recorded') + '\n' +
  '======================================\n\n' +
  (conversationHistory ? 'RECENT CONVERSATION (do not repeat):\n' + conversationHistory + '\n\n' : '') +
  'CLIENT QUESTION: ' + msg.messageText;

return [{ json: {
  systemPrompt, userMessage,
  clientNotFound: false,
  userId: msg.userId, userName: msg.userName, messageText: msg.messageText,
  chatId: msg.chatId, clientName, recordId: chartData.id || null, dashaSource
}}];
